def generate_world_class_2_topic_task(topic_id: str, used_questions: list[str] | None = None) -> dict:
    tasks = TASK_DATA.get(topic_id, TASK_DATA["nature_living_nonliving_2"])
    task = generate_unique_task(lambda: make_choice_task(*random.choice(tasks), topic_id), used_questions)
    task["topic"] = topic_id
    task["topic_title"] = WORLD_CLASS_2_TOPICS.get(topic_id, {}).get("title", "Окружающий мир 2 класс")
    return task
